import type { OrgRole } from '@/types';

interface RoleConfig {
  label: string;
  description: string;
  level: number; // higher = more permissions
}

export const ROLE_CONFIG: Record<OrgRole, RoleConfig> = {
  owner: {
    label: 'Owner',
    description: 'Full control over the organization',
    level: 5,
  },
  admin: {
    label: 'Admin',
    description: 'Manages teams, members, campaigns, and settings',
    level: 4,
  },
  manager: {
    label: 'Manager',
    description: 'Leads a team, assigns tasks, approves requests',
    level: 3,
  },
  member: {
    label: 'Member',
    description: 'Creates task requests, works on assigned tasks',
    level: 2,
  },
  viewer: {
    label: 'Viewer',
    description: 'Read-only access to dashboards and reports',
    level: 1,
  },
};

type Permission =
  | 'org:manage_settings'
  | 'org:create_teams'
  | 'org:invite_users'
  | 'org:assign_roles'
  | 'org:delete'
  | 'campaign:create'
  | 'campaign:approve'
  | 'campaign:delete'
  | 'campaign:view'
  | 'task:create'
  | 'task:approve_requests'
  | 'task:assign'
  | 'task:move_own'
  | 'task:move_any'
  | 'board:view'
  | 'dashboard:view_all'
  | 'dashboard:view_team'
  | 'dashboard:view_own'
  | 'budget:manage'
  | 'data:export'
  | 'attribution:view';

const ROLE_PERMISSIONS: Record<OrgRole, Permission[]> = {
  owner: [
    'org:manage_settings', 'org:create_teams', 'org:invite_users', 'org:assign_roles', 'org:delete',
    'campaign:create', 'campaign:approve', 'campaign:delete', 'campaign:view',
    'task:create', 'task:approve_requests', 'task:assign', 'task:move_own', 'task:move_any',
    'board:view',
    'dashboard:view_all', 'dashboard:view_team', 'dashboard:view_own',
    'budget:manage', 'data:export', 'attribution:view',
  ],
  admin: [
    'org:manage_settings', 'org:create_teams', 'org:invite_users', 'org:assign_roles',
    'campaign:create', 'campaign:approve', 'campaign:delete', 'campaign:view',
    'task:create', 'task:approve_requests', 'task:assign', 'task:move_own', 'task:move_any',
    'board:view',
    'dashboard:view_all', 'dashboard:view_team', 'dashboard:view_own',
    'budget:manage', 'data:export', 'attribution:view',
  ],
  manager: [
    'campaign:create', 'campaign:approve', 'campaign:view',
    'task:create', 'task:approve_requests', 'task:assign', 'task:move_own', 'task:move_any',
    'board:view',
    'dashboard:view_team', 'dashboard:view_own',
    'budget:manage', 'data:export', 'attribution:view',
  ],
  member: [
    'campaign:view',
    'task:move_own',
    'board:view',
    'dashboard:view_own',
  ],
  viewer: [
    'campaign:view',
    'board:view',
    'dashboard:view_own',
    'attribution:view',
  ],
};

export const hasPermission = (role: OrgRole, permission: Permission): boolean => {
  return ROLE_PERMISSIONS[role].includes(permission);
};

export const hasMinRole = (role: OrgRole, minRole: OrgRole): boolean => {
  return ROLE_CONFIG[role].level >= ROLE_CONFIG[minRole].level;
};

export type { Permission };
